282	 * shared eventHandlers map so fireEvent can invoke them later.
283	 */
284	export function buildStartupContext(
285	  eventHandlers: EventHandlerMap,
286	): StartupContext {
287	  return {
288	    on(event: string, handler: (...args: unknown[]) => void | Promise<void>) {
289	      const list = eventHandlers.get(event) ?? [];
290	      list.push(handler);
291	      eventHandlers.set(event, list);
292	    },
293	  };
294	}
295	
