297	 * Fire a lifecycle event, awaiting each handler sequentially.
298	 */
299	export async function fireEvent(
300	  eventHandlers: EventHandlerMap,
301	  event:         string,
302	  ...args: unknown[]
303	): Promise<void> {
304	  const handlers = eventHandlers.get(event) ?? [];
305	  for (const h of handlers) {
306	    await h(...args);
307	  }
308	}
